class CombinationIterator {

    private String characters;
    private int combinationLength;
    private int[] index;
    private int count;

    public CombinationIterator(String characters, int combinationLength) {
        this.characters = characters;
        this.combinationLength = combinationLength;
        this.index = new int[combinationLength];
        this.count = 0;
    }

    public String next() {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < combinationLength; i++) {
            sb.append(characters.charAt(index[i]));
        }
        count++;
        nextIndex();
        return sb.toString();
    }

    public boolean hasNext() {
        return count < factorial(characters.length) / factorial(characters.length - combinationLength);
    }

    private void nextIndex() {
        for (int i = combinationLength - 1; i >= 0; i--) {
            if (index[i] < characters.length - 1) {
                index[i]++;
                for (int j = i + 1; j < combinationLength; j++) {
                    index[j] = index[j - 1] + 1;
                }
                return;
            }
        }
    }

    private int factorial(int n) {
        if (n == 0) {
            return 1;
        }
        return n * factorial(n - 1);
    }
}
